package com.cho2hand.marketplace.service.impl.admin; import com.cho2hand.marketplace.dto.report.AdminReportResponse;import com.cho2hand.marketplace.exception.ListingNotFoundException;import com.cho2hand.marketplace.repository.listing.ListingRepository;import com.cho2hand.marketplace.repository.report.ListingReportRepository;import com.cho2hand.marketplace.service.admin.AdminService;import java.time.Instant;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service @Transactional public class AdminServiceImpl implements AdminService{private final ListingReportRepository reports;private final ListingRepository listings;public AdminServiceImpl(ListingReportRepository r,ListingRepository l){reports=r;listings=l;}@Transactional(readOnly=true) public List<AdminReportResponse> reports(){return reports.findAllByOrderByCreatedAtDesc().stream().map(r->new AdminReportResponse(r.getId(),r.getListingId(),r.getReporterUserId(),r.getReasonId(),r.getDetails(),r.getStatus(),r.getResolutionNote(),r.getResolvedAt(),r.getCreatedAt())).toList();}public void archive(Long id){listings.findById(id).orElseThrow(()->new ListingNotFoundException(id)).setArchivedAt(Instant.now());}public void resolve(Long admin,Long reportId,boolean archive){var report=reports.findById(reportId).orElseThrow(()->new com.cho2hand.marketplace.exception.LookupValueNotFoundException("Report",reportId.toString()));if(archive)archive(report.getListingId());report.resolve(archive?"ARCHIVED":"DISMISSED",null,admin);}}
